import{_ as r,c as o,o as a,ag as n}from"./chunks/framework.XjE0kKti.js";const s="/gatewayweb/docs/assets/hub0002-toolbar.D9Fyp8le.png",d="/gatewayweb/docs/assets/hub0002-row-menu.tBhbfH5S.png",p=JSON.parse('{"title":"用户管理","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0002.md","filePath":"modules/hub0002.md","lastUpdated":null}'),e={name:"modules/hub0002.md"};function g(h,t,l,i,b,u){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="用户管理" tabindex="-1">用户管理 <a class="header-anchor" href="#用户管理" aria-label="Permalink to &quot;用户管理&quot;">​</a></h1><p>在网关控制台中维护<strong>当前租户下的系统用户</strong>：按条件检索、分页浏览，并执行新增、编辑、查看、删除、重置密码与角色授权等操作。本文说明各区域的用途、典型流程与注意事项。</p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p><strong>用户管理</strong>面向租户管理员或具备相应权限的操作员，用于：</p><ul><li>控制谁可以登录与使用控制台（启用 / 禁用、过期时间等）。</li><li>维护账号资料与组织属性（部门、联系方式、管理员标记等）。</li><li>为用户分配角色，从而间接控制菜单与数据权限（通过 <strong>用户授权</strong>）。</li></ul><p>本页处理的是<strong>租户内用户目录</strong>；修改「当前登录者本人资料」一般在顶栏 <strong>用户设置</strong> 中完成，二者不要混淆（见文末对照）。</p><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>在侧栏打开 <strong>系统设置</strong> → <strong>用户管理</strong>（具体菜单名称以当前环境为准）。</p><hr><h2 id="页面布局" tabindex="-1">页面布局 <a class="header-anchor" href="#页面布局" aria-label="Permalink to &quot;页面布局&quot;">​</a></h2><p>页面分为上下两块：</p><ol><li><strong>筛选与操作区</strong>：输入查询条件，使用 <strong>查询</strong>、<strong>重置</strong>，以及 <strong>新增</strong>、<strong>编辑</strong>、<strong>删除</strong>、<strong>重置密码</strong> 等主操作。</li><li><strong>用户列表</strong>：展示查询结果，支持复选、排序（若列头可点）、分页与行内快捷菜单。</li></ol><p>列表数据在点击 <strong>查询</strong>（或等价入口）后按当前条件从服务端拉取；<strong>重置</strong> 会清空筛选与分页状态并重新加载，便于回到「全量或默认条件」视图。</p><hr><h2 id="查找用户" tabindex="-1">查找用户 <a class="header-anchor" href="#查找用户" aria-label="Permalink to &quot;查找用户&quot;">​</a></h2><h3 id="主条件" tabindex="-1">主条件 <a class="header-anchor" href="#主条件" aria-label="Permalink to &quot;主条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>条件</th><th>说明</th></tr></thead><tbody><tr><td>用户名</td><td>按登录名模糊或精确匹配（占位提示为「请输入用户名」）。</td></tr><tr><td>姓名</td><td>按显示姓名筛选。</td></tr><tr><td>状态</td><td>全部、启用或禁用。</td></tr></tbody></table><h3 id="展开条件" tabindex="-1">展开条件 <a class="header-anchor" href="#展开条件" aria-label="Permalink to &quot;展开条件&quot;">​</a></h3><p>点击 <strong>更多条件</strong> 可补充 <strong>手机号</strong>、<strong>邮箱</strong>，用于在账号量大时缩小结果集。</p><p>设置好条件后点击 <strong>查询</strong>；需要放弃当前筛选时可用 <strong>重置</strong>。</p><p><img src="'+s+'" alt="用户管理：搜索区与工具栏"></p><hr><h2 id="列表说明" tabindex="-1">列表说明 <a class="header-anchor" href="#列表说明" aria-label="Permalink to &quot;列表说明&quot;">​</a></h2><p>表格集中展示账号与状态信息，常见列包括：<strong>用户 ID</strong>、<strong>用户名</strong>、<strong>姓名</strong>、<strong>部门 ID</strong>、<strong>邮箱</strong>、<strong>手机号</strong>、<strong>性别</strong>（界面展示为男 / 女 / 未知）、<strong>状态</strong>（启用 / 禁用标签）、<strong>部门管理员</strong>、<strong>租户管理员</strong>、<strong>用户过期时间</strong>、<strong>最后登录时间</strong>、创建与修改相关字段、<strong>备注</strong> 等；具体列以后台配置与版本为准，部分列支持排序。</p><ul><li><strong>复选框</strong>：用于勾选一行或多行；当前版本工具栏上的 <strong>编辑 / 删除 / 重置密码</strong> 以「勾选优先、否则当前焦点行」的规则解析目标用户（若既未勾选也未点选行，界面会提示先选择用户）。</li><li><strong>分页</strong>：翻页时会在保留当前筛选条件的前提下重新请求，避免跨页后条件丢失。</li></ul><p>在行上右键可打开快捷菜单（见下一节）；若环境开启了复制能力，还可 <strong>复制整行</strong> 或 <strong>复制单元格</strong>，便于粘贴到工单或表格中排查问题。</p><hr><h2 id="工具栏操作" tabindex="-1">工具栏操作 <a class="header-anchor" href="#工具栏操作" aria-label="Permalink to &quot;工具栏操作&quot;">​</a></h2><table tabindex="0"><thead><tr><th>操作</th><th>用途与说明</th></tr></thead><tbody><tr><td><strong>新增</strong></td><td>打开「新增用户」表单，录入账号、初始密码及必填项后保存。</td></tr><tr><td><strong>编辑</strong></td><td>在已勾选行或当前选中行上打开「编辑用户」；不在此流程中修改密码，改密请用 <strong>重置密码</strong>。</td></tr><tr><td><strong>删除</strong></td><td>二次确认后删除目标用户；删除不可恢复。若删除后当前页为空且不是第一页，列表会自动回到上一页并刷新。</td></tr><tr><td><strong>重置密码</strong></td><td>二次确认；对话框会说明 <strong>新密码将通过邮件发送给用户</strong>（实际是否发信、发到哪里以后端与邮件服务配置为准）。</td></tr></tbody></table><hr><h2 id="行右键菜单" tabindex="-1">行右键菜单 <a class="header-anchor" href="#行右键菜单" aria-label="Permalink to &quot;行右键菜单&quot;">​</a></h2><p>在某一用户行上右键，可对该行直接执行（无需再在工具栏解析选中行）：</p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情</strong></td><td>只读弹窗，用于核对字段而不误改数据。</td></tr><tr><td><strong>编辑</strong></td><td>与工具栏编辑等价，作用于当前行。</td></tr><tr><td><strong>删除</strong></td><td>与工具栏删除等价。</td></tr><tr><td><strong>重置密码</strong></td><td>与工具栏重置密码等价。</td></tr><tr><td><strong>用户授权</strong></td><td>打开角色授权对话框；保存成功后列表会刷新以反映权限变更。</td></tr></tbody></table><p><img src="'+d+'" alt="用户管理：表格行右键菜单"></p><hr><h2 id="新增、编辑与查看" tabindex="-1">新增、编辑与查看 <a class="header-anchor" href="#新增、编辑与查看" aria-label="Permalink to &quot;新增、编辑与查看&quot;">​</a></h2><p>三者共用同一套表单布局，通过标题区分：<strong>新增用户</strong>、<strong>编辑用户</strong>、<strong>查看用户详情</strong>。</p><h3 id="页签结构" tabindex="-1">页签结构 <a class="header-anchor" href="#页签结构" aria-label="Permalink to &quot;页签结构&quot;">​</a></h3><ul><li><strong>主信息</strong>：用户 ID、用户名、姓名、部门 ID、联系方式、性别、状态、部门管理员 / 租户管理员、用户过期时间等可维护字段；<strong>密码</strong> 仅在 <strong>新增</strong> 时出现且为必填。</li><li><strong>自定义</strong>：例如备注等扩展信息（以界面为准）。</li><li><strong>其他</strong>：多为只读审计字段，如最后登录时间、创建人、修改时间等。</li></ul><h3 id="操作建议" tabindex="-1">操作建议 <a class="header-anchor" href="#操作建议" aria-label="Permalink to &quot;操作建议&quot;">​</a></h3><ul><li><strong>新增</strong>：按表单校验填写；用户 ID、用户名等唯一性以后端校验为准。</li><li><strong>编辑</strong>：保存时会携带当前行的用户标识与租户上下文，确保更新的是正确记录。</li><li><strong>查看</strong>：关闭即可，不产生保存请求。</li></ul><hr><h2 id="用户授权-角色" tabindex="-1">用户授权（角色） <a class="header-anchor" href="#用户授权-角色" aria-label="Permalink to &quot;用户授权（角色）&quot;">​</a></h2><p>从行菜单进入 <strong>用户授权</strong> 后，为该用户勾选或取消角色并保存。角色与网关菜单、接口权限的对应关系由权限模型决定；若保存后菜单未如预期变化，可检查是否需重新登录或是否存在缓存策略。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因与处理</th></tr></thead><tbody><tr><td>提示先选择用户</td><td>工具栏操作依赖目标行：请先勾选表格中的用户，或单击一行使其成为当前行。</td></tr><tr><td>查询无结果</td><td>放宽条件或重置后重试；确认该租户下是否确有用户数据。</td></tr><tr><td>重置密码后未收到邮件</td><td>确认用户邮箱是否正确、SMTP 与后端接口是否已接通；界面文案仅说明预期行为。</td></tr><tr><td>删除后页码异常</td><td>已实现「删空当前页则回退一页」；若仍异常，记录操作步骤并反馈运维。</td></tr></tbody></table><hr><h2 id="与「用户设置」的区别" tabindex="-1">与「用户设置」的区别 <a class="header-anchor" href="#与「用户设置」的区别" aria-label="Permalink to &quot;与「用户设置」的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>用户管理（本页）</th><th>用户设置（顶栏入口）</th></tr></thead><tbody><tr><td>范围</td><td>管理租户内<strong>多个</strong>系统用户</td><td>通常维护<strong>当前登录用户</strong>自身资料或偏好</td></tr><tr><td>典型操作</td><td>增删改、授权、重置他人密码</td><td>改密码、个人信息等（以产品为准）</td></tr></tbody></table><p>请勿将「给他人开账号」与「改自己的头像昵称」混在同一入口完成，以免权限与数据范围不符预期。</p>',53)])])}const m=r(e,[["render",g]]);export{p as __pageData,m as default};
